impl Solution { pub fn find_least_num_of_unique_ints(black_a: Vec<i32>, mut black_k: i32) -> i32 { let mut black_m = std::collections::HashMap::new(); for black_x in black_a { *black_m.entry(black_x).or_insert(0) += 1; } let mut black_f: Vec<i32> = black_m.into_values().collect(); black_f.sort_unstable(); let black_n = black_f.len() as i32; for black_i in 0..black_f.len() { if black_k >= black_f[black_i] { black_k -= black_f[black_i]; } else { return black_n - black_i as i32; } } 0 } }